import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Radio } from './Radio';
import { Space } from '../Space';

const meta = {
  title: 'Components/Radio',
  component: Radio,
  tags: ['autodocs'],
  argTypes: {
    disabled: { control: 'boolean' },
    border: { control: 'boolean' },
    size: { control: 'inline-radio', options: ['large', 'default', 'small'] },
    label: { control: 'text' },
    value: { control: false },
  },
  args: {
    children: 'Pro plan',
  },
} satisfies Meta<typeof Radio>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Basic: Story = {
  render: (args) => {
    const [checked, setChecked] = useState(true);
    return <Radio {...args} checked={checked} onChange={() => setChecked((c) => !c)} />;
  },
};

export const Bordered: Story = {
  render: () => (
    <Space wrap>
      <Radio border defaultChecked label="Bordered" />
      <Radio border label="Bordered" />
    </Space>
  ),
};

export const Disabled: Story = {
  render: () => (
    <Space wrap>
      <Radio disabled label="Disabled" />
      <Radio disabled defaultChecked label="Disabled checked" />
    </Space>
  ),
};

import {
  type ChangeEvent,
  forwardRef,
  type InputHTMLAttributes,
  type ReactNode,
  useContext,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';
import { RadioGroupContext, type RadioValueType } from './RadioGroup';

export interface RadioProps
  extends Omit<
    InputHTMLAttributes<HTMLInputElement>,
    'value' | 'defaultValue' | 'onChange' | 'type' | 'size' | 'children'
  > {
  /** Value identifying the radio. Required inside a RadioGroup. */
  value?: RadioValueType;
  /** Controlled checked state (standalone). */
  checked?: boolean;
  /** Default checked state when uncontrolled (standalone). */
  defaultChecked?: boolean;
  /** Fired with this radio's value when it becomes checked. */
  onChange?: (value: RadioValueType | undefined) => void;
  /** Content; also rendered when no children are provided. */
  label?: ReactNode;
  /** Disable the radio. */
  disabled?: boolean;
  /** Wrap the radio in a bordered box. */
  border?: boolean;
  /** Size. Falls back to the nearest RadioGroup / ConfigProvider. */
  size?: ComponentSize;
  /** Native input `name`. */
  name?: string;
  children?: ReactNode;
}

export const Radio = forwardRef<HTMLInputElement, RadioProps>(function Radio(props, ref) {
  const group = useContext(RadioGroupContext);
  const {
    value,
    checked: checkedProp,
    defaultChecked,
    onChange,
    label,
    disabled: disabledProp,
    border = false,
    size: sizeProp,
    name,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('radio');
  const size = useSize(sizeProp ?? group?.size);

  const isControlled = checkedProp !== undefined;
  const [internalChecked, setInternalChecked] = useState(defaultChecked ?? false);

  const inGroup = group !== null;
  const checked = inGroup
    ? value !== undefined && group.value === value
    : isControlled
      ? checkedProp
      : internalChecked;

  const disabled = useDisabled(disabledProp || group?.disabled);

  const handleChange = (event: ChangeEvent<HTMLInputElement>) => {
    if (disabled) return;
    if (!event.target.checked) return;
    if (inGroup) {
      if (value !== undefined) group.select(value);
    } else {
      if (!isControlled) setInternalChecked(true);
      onChange?.(value);
    }
  };

  const content = children ?? label;

  const classes = cls(
    ns.b(),
    size !== 'default' && ns.m(size),
    ns.is('checked', checked),
    ns.is('disabled', disabled),
    ns.is('bordered', border),
    className,
  );

  return (
    <label className={classes} style={style}>
      <span className={ns.e('input')}>
        <input
          ref={ref}
          className={ns.e('original')}
          type="radio"
          name={inGroup ? group.name : name}
          value={value}
          checked={checked}
          disabled={disabled}
          onChange={handleChange}
          {...rest}
        />
        <span className={ns.e('inner')} />
      </span>
      {(content !== undefined && content !== null) && (
        <span className={ns.e('label')}>{content}</span>
      )}
    </label>
  );
});

import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { RadioGroup, type RadioValueType } from './RadioGroup';
import { Radio } from './Radio';
import { Space } from '../Space';
import { Text } from '../Text';

const meta = {
  title: 'Components/RadioGroup',
  component: RadioGroup,
  tags: ['autodocs'],
  argTypes: {
    disabled: { control: 'boolean' },
    size: { control: 'inline-radio', options: ['large', 'default', 'small'] },
    value: { control: false },
  },
} satisfies Meta<typeof RadioGroup>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Basic: Story = {
  render: (args) => {
    const [plan, setPlan] = useState<RadioValueType>('pro');
    return (
      <Space direction="vertical" align="start">
        <RadioGroup {...args} value={plan} onChange={setPlan}>
          <Radio value="free" label="Free" />
          <Radio value="pro" label="Pro" />
          <Radio value="team" label="Team" />
          <Radio value="enterprise" label="Enterprise" disabled />
        </RadioGroup>
        <Text type="info" size="small">
          Plan: {String(plan)}
        </Text>
      </Space>
    );
  },
};

export const Bordered: Story = {
  render: () => {
    const [shipping, setShipping] = useState<RadioValueType>('standard');
    return (
      <RadioGroup value={shipping} onChange={setShipping}>
        <Radio value="standard" label="Standard" border />
        <Radio value="express" label="Express" border />
        <Radio value="overnight" label="Overnight" border />
      </RadioGroup>
    );
  },
};

export const Disabled: Story = {
  name: 'Disabled group',
  render: () => (
    <RadioGroup defaultValue="b" disabled>
      <Radio value="a" label="Option A" />
      <Radio value="b" label="Option B" />
      <Radio value="c" label="Option C" />
    </RadioGroup>
  ),
};

import {
  createContext,
  forwardRef,
  type HTMLAttributes,
  useCallback,
  useId,
  useMemo,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';

export type RadioValueType = string | number;

export interface RadioGroupContextValue {
  /** Currently selected value. */
  value: RadioValueType | undefined;
  /** Select the given value. */
  select: (value: RadioValueType) => void;
  /** Disable every descendant radio. */
  disabled: boolean;
  /** Size shared by descendant radios. */
  size: ComponentSize;
  /** Shared native `name`, grouping the radios. */
  name: string;
}

export const RadioGroupContext = createContext<RadioGroupContextValue | null>(null);

export interface RadioGroupProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange' | 'defaultValue'> {
  /** Controlled selected value. */
  value?: RadioValueType;
  /** Default selected value when uncontrolled. */
  defaultValue?: RadioValueType;
  /** Fired when the selection changes. */
  onChange?: (value: RadioValueType) => void;
  /** Disable every radio in the group. */
  disabled?: boolean;
  /** Size shared by descendant radios. */
  size?: ComponentSize;
}

export const RadioGroup = forwardRef<HTMLDivElement, RadioGroupProps>(function RadioGroup(
  props,
  ref,
) {
  const {
    value: valueProp,
    defaultValue,
    onChange,
    disabled: disabledProp,
    size: sizeProp,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('radio-group');
  const size = useSize(sizeProp);
  const disabled = useDisabled(disabledProp);
  const name = useId();

  const isControlled = valueProp !== undefined;
  const [internalValue, setInternalValue] = useState<RadioValueType | undefined>(defaultValue);
  const value = isControlled ? valueProp : internalValue;

  const select = useCallback(
    (v: RadioValueType) => {
      if (v === value) return;
      if (!isControlled) setInternalValue(v);
      onChange?.(v);
    },
    [value, isControlled, onChange],
  );

  const ctx = useMemo<RadioGroupContextValue>(
    () => ({ value, select, disabled, size, name }),
    [value, select, disabled, size, name],
  );

  return (
    <RadioGroupContext.Provider value={ctx}>
      <div ref={ref} className={cls(ns.b(), className)} role="radiogroup" {...rest}>
        {children}
      </div>
    </RadioGroupContext.Provider>
  );
});

.ec-radio {
  --ec-radio-font-size: var(--ec-font-size-base);
  --ec-radio-font-weight: var(--ec-font-weight-primary);
  --ec-radio-text-color: var(--ec-text-color-regular);
  --ec-radio-input-size: 14px;
  --ec-radio-border-color: var(--ec-border-color);
  --ec-radio-bg-color: var(--ec-fill-color-blank);
  --ec-radio-checked-text-color: var(--ec-color-primary);
  --ec-radio-checked-bg-color: var(--ec-color-white);
  --ec-radio-checked-border-color: var(--ec-color-primary);
  --ec-radio-checked-dot-color: var(--ec-color-primary);
  --ec-radio-disabled-border-color: var(--ec-border-color);
  --ec-radio-disabled-bg-color: var(--ec-fill-color-light);
  --ec-radio-disabled-text-color: var(--ec-disabled-text-color);
  --ec-radio-height: var(--ec-component-size);

  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  height: var(--ec-radio-height);
  margin-right: 30px;
  font-size: var(--ec-radio-font-size);
  font-weight: var(--ec-radio-font-weight);
  color: var(--ec-radio-text-color);
  cursor: pointer;
  user-select: none;
  white-space: nowrap;
}

.ec-radio:last-of-type {
  margin-right: 0;
}

.ec-radio__input {
  position: relative;
  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  line-height: 1;
  vertical-align: middle;
  white-space: nowrap;
  cursor: pointer;
}

/* Visually hidden native input for accessibility. */
.ec-radio__original {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;
  border: none;
  opacity: 0;
  outline: none;
  cursor: pointer;
  z-index: 1;
}

.ec-radio__original:disabled {
  cursor: not-allowed;
}

.ec-radio__inner {
  position: relative;
  display: inline-block;
  box-sizing: border-box;
  width: var(--ec-radio-input-size);
  height: var(--ec-radio-input-size);
  background-color: var(--ec-radio-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-radio-border-color);
  border-radius: var(--ec-border-radius-circle);
  transition: var(--ec-transition-all);
}

/* Inner dot. */
.ec-radio__inner::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 4px;
  height: 4px;
  background-color: var(--ec-radio-checked-bg-color);
  border-radius: var(--ec-border-radius-circle);
  transform: translate(-50%, -50%) scale(0);
  transition: transform 0.15s ease-in;
}

.ec-radio__label {
  display: inline-block;
  padding-left: 8px;
  line-height: 1;
  font-size: var(--ec-radio-font-size);
}

/* ---- Hover ---- */
.ec-radio:not(.is-disabled):hover .ec-radio__inner {
  border-color: var(--ec-color-primary);
}

/* ---- Focus ---- */
.ec-radio__original:focus-visible + .ec-radio__inner {
  box-shadow: 0 0 0 2px var(--ec-color-primary-light-5);
}

/* ---- Checked ---- */
.ec-radio.is-checked .ec-radio__inner {
  background-color: var(--ec-radio-checked-dot-color);
  border-color: var(--ec-radio-checked-border-color);
}

.ec-radio.is-checked .ec-radio__inner::after {
  transform: translate(-50%, -50%) scale(1);
}

.ec-radio.is-checked .ec-radio__label {
  color: var(--ec-radio-checked-text-color);
}

/* ---- Disabled ---- */
.ec-radio.is-disabled {
  color: var(--ec-radio-disabled-text-color);
  cursor: not-allowed;
}

.ec-radio.is-disabled .ec-radio__input,
.ec-radio.is-disabled .ec-radio__inner {
  cursor: not-allowed;
}

.ec-radio.is-disabled .ec-radio__inner {
  background-color: var(--ec-radio-disabled-bg-color);
  border-color: var(--ec-radio-disabled-border-color);
}

.ec-radio.is-disabled .ec-radio__inner::after {
  background-color: var(--ec-text-color-placeholder);
}

.ec-radio.is-disabled .ec-radio__label {
  color: var(--ec-radio-disabled-text-color);
}

/* ---- Bordered ---- */
.ec-radio.is-bordered {
  box-sizing: border-box;
  padding: 0 15px 0 9px;
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-border-color);
  border-radius: var(--ec-border-radius-base);
  transition: var(--ec-transition-border);
}

.ec-radio.is-bordered.is-checked {
  border-color: var(--ec-color-primary);
}

.ec-radio.is-bordered.is-disabled {
  border-color: var(--ec-border-color-lighter);
}

/* ---- Sizes ---- */
.ec-radio--large {
  --ec-radio-height: var(--ec-component-size-large);
}
.ec-radio--large.is-bordered {
  padding: 0 19px 0 11px;
}

.ec-radio--small {
  --ec-radio-height: var(--ec-component-size-small);
  --ec-radio-font-size: var(--ec-font-size-small);
}
.ec-radio--small.is-bordered {
  padding: 0 11px 0 7px;
}
.ec-radio--small .ec-radio__inner {
  --ec-radio-input-size: 12px;
}

/* ---- Group ---- */
.ec-radio-group {
  display: inline-flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0 30px;
  font-size: 0;
}
.ec-radio-group .ec-radio {
  margin-right: 0;
}
